def get_brain_drainer_phase2c(chapter, difficulty='all', limit=10):
    """Fetch Phase 2C textbook-aligned brain drainers"""
    if chapter not in BRAIN_DRAINERS_PHASE2C:
        return []

    chapter_data = BRAIN_DRAINERS_PHASE2C[chapter]

    if difficulty == 'all':
        questions = []
        for diff in ['easy', 'medium', 'hard']:
            questions.extend(chapter_data.get(diff, []))
    else:
        questions = chapter_data.get(difficulty, [])

    return questions[:limit] if limit else questions

def get_all_brain_drainers_phase2c(chapter):
    """Get all Phase 2C brain drainers for a chapter"""
    if chapter not in BRAIN_DRAINERS_PHASE2C:
        return []

    chapter_data = BRAIN_DRAINERS_PHASE2C[chapter]
    all_questions = []

    for diff in ['easy', 'medium', 'hard']:
        all_questions.extend(chapter_data.get(diff, []))

    return all_questions

